('Alfred Gratien', 'alfred-gratien', 'NM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Épernay', 'Marne', '30 Rue Maurice Cerveaux, 51200 Épernay', '+33 3 26 54 38 20', 'www.alfredgratien.com', 1864, 'Henkell & Co', 'Henkell & Co', 'Nicolas Jaeger', 'Nicolas Jaeger', NULL, NULL, NULL, 30, 35, 35, ARRAY[]::text[], 'Coquard tradizionale', 'piccole botti di rovere', 'svolta', 300000, NULL, NULL, true, true,
