('Damien Hugot', 'damien-hugot', 'RM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Épernay', 'Marne', NULL, NULL, NULL, NULL, 'Damien Hugot', 'Indipendente', 'Damien Hugot', 'Damien Hugot', NULL, NULL, NULL, 35, 35, 30, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
