('Lucien Collard', 'lucien-collard', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Bouzy', 'Marne', NULL, NULL, NULL, NULL, 'Famille Collard', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 80, 15, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Vigneron di Bouzy, Grand Cru della Montagne de Reims. Champagne da Pinot Noir di grande autenticità e struttura da uno dei crus più celebri per il vitigno.', 'Il Grand Cru Bouzy come terroir di vocazione per il Pinot Noir champenois.', '€€€', false),

('Maillart', 'maillart', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Nanteuil-la-Forêt', 'Marne', NULL, NULL, NULL, NULL, 'Famille Maillart', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 45, 30, 25, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Vigneron di Nanteuil-la-Forêt nella Montagne de Reims occidentale. Champagne di carattere da un terroir meno noto ma di grande personalità, con vigne su suoli calcareo-gessosi.', 'La Montagne de Reims occidentale come territorio di espressione autentica e ancora poco esplorata dalla critica internazionale.', '€€€', false),

('Mailly', 'mailly-cm', 'CM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Mailly-Champagne', 'Marne', '28 Rue de la Libération, 51500 Mailly-Champagne', '+33 3 26 49 41 10', 'www.champagne-mailly.com', 1929, 'Coopérative de Mailly', 'Cooperativa', NULL, 'Hervé Dantan', 75, 75, NULL, 75, 20, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', 500000, NULL, NULL, true, false,
 'Cooperativa di eccellenza fondata nel 1929 nel Grand Cru Mailly-Champagne. Produce champagne esclusivamente da uve del proprio Grand Cru, con grande coerenza stilistica. Il Blanc de Noirs e la cuvée Les Échansons sono tra le referenze più apprezzate della cooperativa.', 'Un solo Grand Cru per tutti i vini: la cooperativa di Mailly dimostra che qualità e cooperazione non sono concetti opposti, ma alleati naturali.', '€€€', false),

('Mandois', 'mandois', 'NM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Pierry', 'Marne', '66 Rue du Général de Gaulle, 51530 Pierry', '+33 3 26 54 03 18', 'www.champagne-mandois.fr', 1735, 'Famille Mandois', 'Indipendente', 'Claude Mandois', 'Claude Mandois', 30, 30, NULL, 40, 35, 25, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', 400000, NULL, NULL, true, true,
 'Maison storica di Pierry fondata nel 1735, tra le più antiche ancora a conduzione familiare della Champagne. Claude Mandois guida l''azienda con champagne di grande eleganza e identità territoriale. Il Victor Mandois millesimato è la cuvée di punta.', 'Quasi tre secoli di storia familiare a Pierry: la continuità come valore supremo e l''eleganza come stile riconoscibile attraverso le generazioni.', '€€€', false),

('Manon Boutillez-Guer', 'manon-boutillez-guer', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Villers-Marmery', 'Marne', NULL, NULL, NULL, NULL, 'Manon Boutillez-Guer', 'Indipendente', 'Manon Boutillez-Guer', 'Manon Boutillez-Guer', NULL, NULL, NULL, 10, 80, 10, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Giovane vigneronne con vigne a Villers-Marmery, Premier Cru atipico della Montagne de Reims dominato da Chardonnay in zona tipicamente a Pinot Noir. Champagne di bella tensione e originalità.', 'La nuova generazione della Montagne de Reims: Chardonnay in un terroir vocato al Pinot Noir per champagne di grande originalità stilistica.', '€€€', false),

('Marc Hébrart', 'marc-hebrart', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Mareuil-sur-Aÿ', 'Marne', '18-20 Rue du Pont, 51160 Mareuil-sur-Aÿ', '+33 3 26 52 60 75', 'www.champagne-hebrart.com', 1964, 'Jean-Paul Hébrart', 'Indipendente', 'Jean-Paul Hébrart', 'Jean-Paul Hébrart', 14, 14, NULL, 50, 45, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox e legno', 'svolta parziale', 100000, NULL, NULL, false, true,
 'Jean-Paul Hébrart è tra i più rispettati vigneron della regione, con vigne tra Mareuil-sur-Aÿ, Aÿ e la Côte des Blancs. I suoi champagne — in particolare la Sélection e il Blanc de Blancs Cuvée de Suzel — esprimono un equilibrio perfetto tra struttura e finezza.', 'L''equilibrio come vocazione: vigne a cavallo tra Montagne de Reims e Côte des Blancs per champagne che coniugano struttura da Pinot Noir e finezza da Chardonnay con rara armonia.', '€€€', false),

('Marie Courtin', 'marie-courtin', 'RM', NULL, 'Polisy', 'Aube', NULL, NULL, NULL, NULL, 'Dominique Moreau', 'Indipendente', 'Dominique Moreau', 'Dominique Moreau', 4, 4, NULL, 90, 5, 5, ARRAY['Biodinamica', 'Demeter']::text[], 'pneumatica', 'botti di rovere usate', 'non svolta', 15000, NULL, 'Vino e Design', false, false,
 'Dominique Moreau produce a Polisy, nell''Aube, champagne naturali di grande profondità e carattere. Spesso senza aggiunta di solforosa, fermentazioni spontanee e vigne biodinamiche. Efflorescence e Resonance sono tra i vini più originali e toccanti di tutta la Champagne.', 'La natura come maestra: biodinamica integrale nell''Aube, fermentazioni spontanee e zero solforosa per champagne che esprimono la purezza di un territorio autentico e fuori dalle convenzioni.', '€€€€', false),

('Matthieu Cugnart', 'matthieu-cugnart', 'RM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Villers-sous-Châtillon', 'Marne', NULL, NULL, NULL, NULL, 'Matthieu Cugnart', 'Indipendente', 'Matthieu Cugnart', 'Matthieu Cugnart', NULL, NULL, NULL, 25, 25, 50, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Giovane vigneron di Villers-sous-Châtillon nella Valle della Marna con approccio artigianale. Champagne di carattere che valorizzano il Meunier del territorio.', 'La Valle della Marna e il Meunier come territorio e vitigno di riferimento per una giovane generazione di vigneron.', '€€€', false),

('Maurice Choppin', 'maurice-choppin', 'RM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Leuvrigny', 'Marne', NULL, NULL, NULL, NULL, 'Famille Choppin', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 20, 20, 60, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Vigneron di Leuvrigny nella Valle della Marna con champagne di carattere artigianale. Produzione tradizionale con forte identità territoriale.', 'La tradizione vitivinicola della Valle della Marna in tutta la sua autenticità artigianale.', '€€', false),

('Moussé', 'mousse', 'RM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Cuisles', 'Marne', '2 Rue Bailly, 51700 Cuisles', '+33 3 26 58 10 80', 'www.champagne-mousse.fr', NULL, 'Cédric Moussé', 'Indipendente', 'Cédric Moussé', 'Cédric Moussé', 7, 7, NULL, 10, 10, 80, ARRAY[]::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta parziale', 50000, NULL, 'Vino e Design', false, true,
 'Cédric Moussé è uno dei più grandi interpreti del Pinot Meunier al mondo. I suoi champagne da Cuisles, nella Valle della Marna, dimostrano che il Meunier può raggiungere vette di complessità solitamente attribuite solo a Chardonnay e Pinot Noir. L''Or d''Eugène è un capolavoro assoluto.', 'La riabilitazione del Meunier: Cédric Moussé dimostra che il vitigno più piantato della Champagne, in mani esperte e su terroir vocati, produce champagne di straordinaria complessità e bevibilità.', '€€€', false),

('Odile Thieuillet', 'odile-thieuillet', 'RM', NULL, 'Baroville', 'Aube', NULL, NULL, NULL, NULL, 'Odile Thieuillet', 'Indipendente', 'Odile Thieuillet', 'Odile Thieuillet', NULL, NULL, NULL, 85, 10, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Vigneronne dell''Aube con approccio naturale e champagne di grande carattere da Pinot Noir. Espressione autentica del territorio meridionale della Champagne.', 'Il Pinot Noir dell''Aube da una vigneronne che porta freschezza e autenticità in un territorio ancora poco conosciuto.', '€€€', false),

('Pascal Agrapart', 'pascal-agrapart', 'RM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Avize', 'Marne', '57 Avenue Jean Jaurès, 51190 Avize', '+33 3 26 57 51 38', 'www.champagne-agrapart.com', 1894, 'Famille Agrapart', 'Indipendente', 'Pascal Agrapart', 'Pascal e Samuel Agrapart', 10, 10, NULL, 0, 97, 3, ARRAY[]::text[], 'pneumatica', 'botti di rovere usate e acciaio', 'svolta parziale', 70000, NULL, 'Vino e Design', false, true,
 'Pascal Agrapart è uno dei più grandi interpreti della Côte des Blancs. Vigne nei Grand Crus di Avize, Cramant, Oger e Oiry per champagne di straordinaria precisione. Minéral, Terroirs, Vénus, Avizoise e Expérience sono tra i Blanc de Blancs più complessi e ricercati esistenti.', 'Il Grand Cru Côte des Blancs nella sua forma più pura: Pascal Agrapart coniuga rigore tecnico e sensibilità artigianale per champagne che esprimono la quintessenza del Chardonnay champenois.', '€€€€', false),

('Paul Déthune', 'paul-dethune', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Ambonnay', 'Marne', '2 Rue du Moulin, 51150 Ambonnay', '+33 3 26 57 01 88', 'www.champagne-dethune.com', 1880, 'Pierre Déthune', 'Indipendente', 'Pierre Déthune', 'Pierre Déthune', 7, 7, NULL, 80, 15, 5, ARRAY[]::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta', 60000, NULL, NULL, false, true,
 'Domaine storico di Ambonnay, Grand Cru della Montagne de Reims per eccellenza del Pinot Noir. Pierre Déthune produce champagne di grande struttura con vigne centenarie su suoli calcareo-gessosi. La Cuvée Prestige e il Clos des Moulins sono di rara profondità e longevità.', 'Ambonnay Grand Cru come terroir per il Pinot Noir champenois: vigne centenarie e artigianalità millenaria per champagne di struttura borgognona.', '€€€', false),

('Pertois-Moriset', 'pertois-moriset', 'RM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Le Mesnil-sur-Oger', 'Marne', '2 Place du Général de Gaulle, 51190 Le Mesnil-sur-Oger', '+33 3 26 57 51 40', 'www.champagne-pertois-moriset.com', 1951, 'Famille Pertois', 'Indipendente', NULL, NULL, 12, 12, NULL, 0, 100, 0, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', 100000, NULL, NULL, false, true,
 'Domaine storico di Le Mesnil-sur-Oger con vigne nei Grand Crus della Côte des Blancs. Blanc de Blancs di grande mineralità gessosa, verticalità e longevità eccezionale da uno dei terroir più illustri della Champagne.', 'Il Le Mesnil-sur-Oger come eredità: decenni di lavoro sullo stesso terroir gessoso per Blanc de Blancs che esprimono la quintessenza del Grand Cru.', '€€€', false),

('Philipponnat', 'philipponnat', 'NM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Mareuil-sur-Aÿ', 'Marne', '13 Rue du Pont, 51160 Mareuil-sur-Aÿ', '+33 3 26 56 93 00', 'www.philipponnat.com', 1910, 'Lanson-BCC', 'Lanson-BCC Group', 'Charles Philipponnat', 'Émilien Boutillat', 20, 20, NULL, 55, 35, 10, ARRAY[]::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta parziale', 500000, NULL, 'Rinaldi Importatori', true, true,
 'Maison fondata nel 1910, celebre per il Clos des Goisses — 5,5 ettari in forte pendio sul Marne, uno dei clos più iconici e costosi di tutta la Champagne. Charles Philipponnat produce champagne di grande struttura e capacità di invecchiamento con fermentazione parziale in legno.', 'Il Clos des Goisses come vertice: una vigna unica, un microclima eccezionale e decenni di affinamento per champagne che sfidano il tempo e la gravità — letteralmente.', '€€€€', false),

('Pierre Gerbais', 'pierre-gerbais', 'RM', NULL, 'Celles-sur-Ource', 'Aube', '6 Rue de Balnot, 10110 Celles-sur-Ource', '+33 3 25 38 56 59', 'www.champagne-gerbais.fr', NULL, 'Aurélie Gerbais', 'Indipendente', 'Aurélie Gerbais', 'Aurélie Gerbais', 10, 10, NULL, 60, 30, 10, ARRAY[]::text[], 'pneumatica', 'acciaio inox e legno', 'svolta parziale', 80000, NULL, 'Vino e Design', false, true,
 'Aurélie Gerbais porta avanti il domaine di famiglia a Celles-sur-Ource nell''Aube con grande personalità. I suoi champagne valorizzano il Pinot Blanc — vitigno rarissimo — accanto al Pinot Noir dell''Aube. L''Origine e il Grains de Celles sono espressioni uniche del territorio.', 'Il Pinot Blanc come tesoro nascosto: Aurélie Gerbais è tra i pochi a valorizzare questo vitigno dimenticato dell''Aube, con champagne di grande originalità e carattere.', '€€€', false),

('Pierre Legras', 'pierre-legras', 'RM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Chouilly', 'Marne', NULL, NULL, NULL, NULL, 'Famille Legras', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 0, 100, 0, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Vigneron di Chouilly, Grand Cru della Côte des Blancs. Blanc de Blancs di grande eleganza e finezza da un terroir che esprime lo Chardonnay nella sua versione più floreale.', 'Il Grand Cru Chouilly come terroir di elezione per un Blanc de Blancs di grande eleganza e finezza.', '€€€', false),

('Pierre Paillard', 'pierre-paillard', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Bouzy', 'Marne', '2 Rue du 19 Janvier, 51150 Bouzy', '+33 3 26 57 08 04', 'www.champagne-pierre-paillard.com', 1946, 'Antoine e Louis Paillard', 'Indipendente', 'Antoine Paillard', 'Antoine e Louis Paillard', 9, 9, NULL, 70, 25, 5, ARRAY[]::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta parziale', 70000, NULL, 'Vino e Design', false, true,
 'Antoine e Louis Paillard gestiscono il domaine di Bouzy con grande rigore e passione. I loro champagne — in particolare Le Mottelette e Les Maillerettes parcellaires — esprimono il Grand Cru Bouzy con profondità e longevità straordinarie. Tra i riferimenti assoluti del movimento vigneron.', 'Il Grand Cru Bouzy attraverso singole parcelle: Antoine e Louis Paillard dimostrano come un territorio già grande possa diventare straordinario quando viene esplorato con la precisione della vigna singola.', '€€€', false),

('Piper-Heidsieck', 'piper-heidsieck', 'NM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Reims', 'Marne', '51 Boulevard Henry Vasnier, 51100 Reims', '+33 3 26 84 43 00', 'www.piper-heidsieck.com', 1785, 'Groupe EPI', 'EPI', 'Cyril Lignac (consulente)', 'Emilien Boutillat', NULL, NULL, NULL, 40, 35, 25, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', 5000000, NULL, 'Rinaldi Importatori', true, false,
 'Una delle grandi Maison storiche di Reims, fondata nel 1785. La Cuvée Rare Millésimé è considerata tra le prestige cuvée più sottovalutate — e straordinarie — della Champagne per complessità e longevità. Oggi di proprietà EPI, ha ritrovato un''identità stilistica forte sotto la guida di Emilien Boutillat.', 'Il riscatto della grande storia: Piper-Heidsieck riscopre le proprie radici aristocratiche attraverso la Cuvée Rare, uno champagne di profondità e longevità che merita un posto tra le grandi prestige cuvée mondiali.', '€€€', false),

('Pommery', 'pommery', 'NM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Reims', 'Marne', '5 Place du Général Gouraud, 51100 Reims', '+33 3 26 61 62 63', 'www.pommery.com', 1858, 'Groupe Vranken', 'Vranken-Pommery', 'Thierry Gasco', 'Thierry Gasco', 300, 300, NULL, 35, 40, 25, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', 8000000, NULL, NULL, true, false,
 'Grande Maison di Reims fondata nel 1858. Louise Pommery ha inventato il Brut moderno nel 1874 — prima di lei lo champagne era sempre dolce. Le crayères gallo-romane sotto la Maison, profonde 30 metri e patrimonio UNESCO, ospitano milioni di bottiglie. Il Cuvée Louise è la prestige cuvée di riferimento.', 'L''invenzione del Brut moderno come legacy: Louise Pommery ha cambiato per sempre il mondo dello champagne nel 1874 e le sue crayères romane sono ancora oggi un patrimonio dell''umanità sotto Reims.', '€€€', false),

('Pouillon', 'pouillon', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Mareuil-sur-Aÿ', 'Marne', NULL, NULL, NULL, NULL, 'Famille Pouillon', 'Indipendente', 'Fabrice Pouillon', 'Fabrice Pouillon', NULL, NULL, NULL, 50, 35, 15, ARRAY['HVE']::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Vigneron di Mareuil-sur-Aÿ con approccio biologico e grande attenzione alla sostenibilità in vigna. Champagne di grande bevibilità e carattere territoriale.', 'La sostenibilità come scelta consapevole: viticoltura biologica a Mareuil-sur-Aÿ per champagne autentici e rispettosi dell''ambiente.', '€€€', false)

ON CONFLICT (slug) DO NOTHING;

