INSERT INTO maison (nome, slug, tipo, zona_id, sede_comune, sede_regione, sede_indirizzo, telefono, sito_web, anno_fondazione, proprieta, gruppo, direzione, chef_de_cave, ettari_totali, ettari_proprieta, ettari_gestione, pct_pinot_noir, pct_chardonnay, pct_meunier, certificazioni, tipo_pressa, vinificazione, malolattica, produzione_bottiglie, stock_cantina, importatore_italia, visita_possibile, degustazione_possibile, descrizione, filosofia, fascia_prezzo, is_free) VALUES

-- ── R ──────────────────────────────────────────────────────────

('R. Faivre', 'r-faivre', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', NULL, 'Marne', NULL, NULL, NULL, NULL, 'Famille Faivre', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 50, 30, 20, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Piccolo vigneron della Montagne de Reims con champagne di carattere artigianale. Produzione in piccole quantità con forte identità territoriale e rispetto per la tradizione champenoise.', 'L''artigianalità come scelta: champagne autentici da un piccolo récoltant della Montagne de Reims.', '€€', false),

('Rare Champagne', 'rare-champagne', 'NM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Reims', 'Marne', '51 Boulevard Henry Vasnier, 51100 Reims', NULL, 'www.rarechampagne.com', 2019, 'Groupe EPI', 'EPI', NULL, 'Émilien Boutillat', NULL, NULL, NULL, 40, 45, 15, ARRAY[]::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta parziale', NULL, NULL, NULL, false, false,
 'Nata come prestige cuvée di Piper-Heidsieck nel 1976, Rare Champagne è stata rilanciata come marchio autonomo nel 2019. Produce solo due referenze: Rare Millésimé Blanc e Rare Millésimé Rosé, entrambi di straordinaria profondità e complessità da annate eccezionali con lungo affinamento. Tra le prestige cuvée più sottovalutate dalla critica internazionale.', 'Due soli vini, di eccellenza assoluta: la selezione massimale dei vins de base e l''affinamento prolungato come condizioni irrinunciabili per cuvée che sfidano il tempo.', '€€€€', false),

('Régis Poissinet', 'regis-poissinet', 'RM', NULL, 'Essoyes', 'Aube', NULL, NULL, NULL, NULL, 'Régis Poissinet', 'Indipendente', 'Régis Poissinet', 'Régis Poissinet', 7, 7, NULL, 70, 15, 10, ARRAY[]::text[], 'pneumatica', 'acciaio inox e legno', 'svolta parziale', 40000, NULL, 'Vino e Design', false, true,
 'Vigneron dell''Aube con approccio sperimentale e curiosità intellettuale rara. Régis Poissinet lavora con Pinot Noir ma soprattutto valorizza vitigni antichi rarissimi come l''Arbane — sopravvissuto solo in pochi ettari della Champagne. I suoi champagne sono originali, profondi e inclassificabili, tra i più discussi del nuovo movimento artigianale.', 'L''Aube come laboratorio: vitigni antichi, metodi naturali e lo spirito del ricercatore per champagne che allargano i confini di ciò che lo champagne può essere.', '€€€', false),

('Rémi Georgeton', 'remi-georgeton', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Verzenay', 'Marne', NULL, NULL, NULL, NULL, 'Rémi Georgeton', 'Indipendente', 'Rémi Georgeton', 'Rémi Georgeton', NULL, NULL, NULL, 80, 15, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Giovane vigneron di Verzenay, Grand Cru della Montagne de Reims. Champagne di grande struttura da Pinot Noir coltivato su suoli calcareo-gessosi in uno dei crus più importanti della regione per il vitigno.', 'Verzenay Grand Cru come terroir di espressione: Pinot Noir di struttura e profondità in un giovane récoltant di grande talento.', '€€€', false),

('Éric Rodez', 'eric-rodez', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Ambonnay', 'Marne', '4 Rue de Isse, 51150 Ambonnay', '+33 3 26 57 04 93', 'www.champagne-ericrodez.com', NULL, 'Éric Rodez', 'Indipendente', 'Éric Rodez', 'Éric Rodez', 6, 6, NULL, 75, 20, 5, ARRAY[]::text[], 'pneumatica', 'botti di rovere usate e acciaio', 'svolta parziale', 55000, NULL, 'Vino e Design', false, true,
 'Éric Rodez è uno dei grandi maestri del Pinot Noir champenois con vigne nel Grand Cru Ambonnay. Botti usate, serbatoi inox, zero filtrazione, dosaggi minimi. Cuvée des Crayères, Empreinte e il Blanc de Noirs sono referenze assolute del movimento vigneron. Cofondatore con David Léclapart del rinnovamento qualitativo dei récoltants champenois.', 'Il Grand Cru Ambonnay con la complessità dei grandi Borgogna: Éric Rodez esprime il Pinot Noir senza compromessi in cantina, per champagne che invecchiano magnificamente.', '€€€', false),

('Roger Brun', 'roger-brun', 'RM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Aÿ', 'Marne', '6 Rue des Fossés, 51160 Aÿ', '+33 3 26 54 21 11', 'www.champagne-roger-brun.com', 1773, 'Famille Brun', 'Indipendente', 'Guillaume Brun', 'Guillaume Brun', 7, 7, NULL, 65, 30, 5, ARRAY[]::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta parziale', 50000, NULL, NULL, false, true,
 'Una delle famiglie vitivinicole più antiche di Aÿ Grand Cru, con radici documentate al 1773. Guillaume Brun produce champagne di grande struttura da Pinot Noir del Grand Cru Aÿ con vinificazione parziale in legno. Les Cépages, il Blanc de Blancs e i parcellaires completano una gamma di grande coerenza stilistica.', 'Quasi 250 anni di storia ad Aÿ: Guillaume Brun porta avanti una delle eredità familiari più lunghe della Champagne con champagne di struttura classica e identità Grand Cru inconfondibile.', '€€€', false),

('Rousseaux-Batteux', 'rousseaux-batteux', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Verzy', 'Marne', NULL, NULL, NULL, NULL, 'Famille Rousseaux', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 80, 15, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Piccolo vigneron di Verzy, Premier Cru della Montagne de Reims. Champagne di grande carattere da Pinot Noir in uno dei comuni più particolari della regione, celebre per i famosi faux de Verzy — faggi contorti con genetica unica — che danno a questo cru un''aura di singolarità.', 'Verzy e la sua unicità biologica e geologica come ispirazioni per champagne di carattere autentico, fuori dagli schemi commerciali.', '€€€', false),

-- ── S ──────────────────────────────────────────────────────────

('Delamotte', 'delamotte', 'NM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Le Mesnil-sur-Oger', 'Marne', '7 Rue de la Brèche d''Oger, 51190 Le Mesnil-sur-Oger', '+33 3 26 57 51 65', 'www.salondelamotte.com', 1760, 'Laurent-Perrier', 'Laurent-Perrier Group', 'Didier Depond', 'Didier Depond', NULL, NULL, NULL, 5, 92, 3, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', 500000, NULL, 'Pellegrini SpA', true, true,
 'Fondata nel 1760, Delamotte è la maison sorella di Salon — entrambe di proprietà del gruppo Laurent-Perrier con sede a Le Mesnil-sur-Oger. Il Blanc de Blancs de la Côte des Blancs ha una purezza e verticalità gessosa di straordinaria eleganza. Considerata la porta d''ingresso stilistica al mondo di Salon, con lo stesso terroir e la stessa squadra a un prezzo più accessibile.', 'L''eleganza del Mesnil-sur-Oger resa accessibile: Delamotte produce Blanc de Blancs di grande precisione minerale che rispecchiano lo stesso terroir leggendario di Salon.', '€€€', false),

('Salon', 'salon', 'NM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Le Mesnil-sur-Oger', 'Marne', '7 Rue de la Brèche d''Oger, 51190 Le Mesnil-sur-Oger', '+33 3 26 57 51 65', 'www.salondelamotte.com', 1905, 'Laurent-Perrier', 'Laurent-Perrier Group', 'Didier Depond', 'Didier Depond', 1, 1, NULL, 0, 100, 0, ARRAY[]::text[], 'Coquard tradizionale', 'botti di rovere usate', 'svolta', 60000, NULL, 'Pellegrini SpA', true, true,
 'Un solo vino, un solo anno, un solo vitigno, un solo cru. Salon è forse il produttore più leggendario dell''intera Champagne. Fondato da Eugène-Aimé Salon nel 1905, produce esclusivamente Blanc de Blancs da Le Mesnil-sur-Oger Grand Cru solo nelle annate eccezionali — raramente più di 5-6 millesimi per decennio. Un millesimo Salon in cantina è il sogno di ogni collezionista.', 'La perfezione come unico standard: se l''annata non è eccezionale, il vino non viene commercializzato. Un solo vino, un solo villaggio, un solo vitigno, un solo cru — la definizione stessa di vin de terroir.', '€€€€€', false),

('Savart', 'savart', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Écueil', 'Marne', NULL, NULL, NULL, NULL, 'Frédéric Savart', 'Indipendente', 'Frédéric Savart', 'Frédéric Savart', 6, 6, NULL, 60, 35, 5, ARRAY[]::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta parziale', 50000, NULL, 'Vino e Design', false, true,
 'Frédéric Savart è uno dei vigneron più apprezzati dalla critica internazionale. Da Écueil, Premier Cru della Montagne de Reims, produce champagne di grande finezza con vinificazione parziale in legno. L''Ouverture, L''Accomplie e le cuvée parcellaires sono tra i vini più ricercati del movimento artigianale champenois.', 'Écueil Premier Cru come terroir di elezione: Frédéric Savart coniuga rigore tecnico e sensibilità artigianale per champagne di finezza e profondità borgognona.', '€€€', false),

('Stéphane Regnault', 'stephane-regnault', 'RM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Oger', 'Marne', NULL, NULL, NULL, NULL, 'Stéphane Regnault', 'Indipendente', 'Stéphane Regnault', 'Stéphane Regnault', NULL, NULL, NULL, 0, 100, 0, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Vigneron della Côte des Blancs con vigne nel Grand Cru Oger. Blanc de Blancs di grande purezza gessosa da uno dei crus più eleganti della regione, meno noto di Avize e Mesnil ma di assoluta classe.', 'Il Grand Cru Oger come terroir di espressione per Blanc de Blancs di grande eleganza e finezza calcarea.', '€€€', false),

('Tarlant', 'tarlant', 'RM', '08daee1e-4c45-4961-9e87-d20c6bac0972', 'Oeuilly', 'Marne', '21 Rue de la Coopérative, 51480 Oeuilly', '+33 3 26 58 30 60', 'www.tarlant.com', 1687, 'Famille Tarlant', 'Indipendente', 'Benoît e Mélanie Tarlant', 'Benoît e Mélanie Tarlant', 14, 14, NULL, 40, 30, 30, ARRAY['HVE']::text[], 'pneumatica', 'botti di rovere e acciaio', 'svolta parziale', 130000, NULL, 'Vino e Design', false, true,
 'Benoît e Mélanie Tarlant portano avanti una storia familiare straordinaria ad Oeuilly nella Valle della Marna. La gamma Zero (Brut Nature senza dosaggio) è diventata un manifesto per l''intera generazione di champagne naturali. BAM!, La Vigne d''Or, Zero Blanc de Blancs e i singoli clos parcellaires sono tra le espressioni più originali e convincenti del movimento vigneron.', 'Il Brut Nature come filosofia: Benoît e Mélanie Tarlant credono che il grande champagne non abbia bisogno del dosaggio. Ogni vino deve essere abbastanza ricco e complesso da stare in piedi da solo.', '€€€', false),

-- ── V ──────────────────────────────────────────────────────────

('Veuve Fourny', 'veuve-fourny', 'RM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Vertus', 'Marne', '5 Rue du Mesnil, 51130 Vertus', '+33 3 26 52 16 30', 'www.champagne-veuve-fourny.com', 1856, 'Charles-Henri et Emmanuel Fourny', 'Indipendente', 'Charles-Henri Fourny', 'Emmanuel Fourny', 9, 9, NULL, 5, 90, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox e legno', 'svolta parziale', 80000, NULL, NULL, false, true,
 'Charles-Henri ed Emmanuel Fourny guidano questo domaine storico di Vertus, Premier Cru della Côte des Blancs. I loro Blanc de Blancs — in particolare Monts Ferrés e le singole vigne di Vertus — esprimono la finezza e la profondità di un Premier Cru che molti considerano degno di Grand Cru. Dosaggi minimi e grande eleganza definiscono lo stile.', 'Vertus Premier Cru come terroir di eccellenza: Charles-Henri ed Emmanuel Fourny dimostrano che il confine tra Premier e Grand Cru è spesso una questione di attenzione e artigianalità, non di suolo.', '€€€', false),

('Vilmart & Cie', 'vilmart', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Rilly-la-Montagne', 'Marne', '4 Rue de la République, 51500 Rilly-la-Montagne', '+33 3 26 03 40 01', 'www.vilmart-champagne.com', 1890, 'Laurent Champs', 'Indipendente', 'Laurent Champs', 'Laurent Champs', 11, 11, NULL, 45, 45, 10, ARRAY[]::text[], 'pneumatica', 'grandi botti di rovere', 'svolta', 100000, NULL, 'Vino e Design', true, true,
 'Laurent Champs è uno dei maestri assoluti della fermentazione in legno in Champagne. A Rilly-la-Montagne, Premier Cru, fermenta tutti i vini in grandi fûts di rovere (228 litri), ottenendo champagne di straordinaria complessità e struttura. Grand Cellier, Grand Cellier d''Or e Cœur de Cuvée sono tra i vini più longevi e raffinati della Montagne de Reims.', 'La quercia come linguaggio: Laurent Champs fermenta in grandi fûts per champagne di complessità borgognona — il legno non si sente ma si percepisce in ogni strato di profondità e persistenza.', '€€€', false),

('Voirin-Jumel', 'voirin-jumel', 'RM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Cramant', 'Marne', '777 Rue de la République, 51530 Cramant', '+33 3 26 57 55 22', NULL, NULL, 'Famille Voirin', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 0, 100, 0, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, true,
 'Vigneron di Cramant, Grand Cru della Côte des Blancs per eccellenza. Blanc de Blancs di grande purezza e finezza gessosa da uno dei crus più celebri per lo Chardonnay champenois, con una mineralità fragrante e lunghissima.', 'Il Grand Cru Cramant come terroir di vocazione assoluta per Blanc de Blancs di eleganza, mineralità e affilata freschezza.', '€€€', false),

-- ── W ──────────────────────────────────────────────────────────

('Waris-Hubert', 'waris-hubert', 'RM', '91b7c08e-b280-4172-a43b-8d9c886df946', 'Avize', 'Marne', NULL, NULL, NULL, NULL, 'Manon Waris', 'Indipendente', 'Manon Waris', 'Manon Waris', NULL, NULL, NULL, 0, 100, 0, ARRAY[]::text[], 'pneumatica', 'acciaio inox e legno', 'svolta parziale', NULL, NULL, NULL, false, false,
 'Manon Waris produce a Avize, Grand Cru della Côte des Blancs, Blanc de Blancs di grande mineralità gessosa. Giovane vigneronne che rappresenta la nuova generazione artigianale femminile della Champagne, con champagne di grande purezza e tensione calcarea.', 'La nuova generazione al Grand Cru Avize: Blanc de Blancs di grande purezza da vigne coltivate con rispetto per la tradizione e sensibilità contemporanea.', '€€€', false),

-- ── Completamento lista ─────────────────────────────────────────

('Maxence Janisson', 'maxence-janisson', 'RM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Verzenay', 'Marne', NULL, NULL, NULL, NULL, 'Maxence Janisson', 'Indipendente', 'Maxence Janisson', 'Maxence Janisson', NULL, NULL, NULL, 80, 15, 5, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Giovane vigneron di Verzenay, Grand Cru della Montagne de Reims. Champagne di grande struttura e profondità da Pinot Noir coltivato su suoli calcareo-gessosi di uno dei Grand Crus più importanti per il vitigno.', 'Verzenay Grand Cru come terroir di elezione: Pinot Noir di struttura e bevibilità straordinarie da un giovane récoltant di talento.', '€€€', false),

('Palmer & Co', 'palmer-co', 'CM', '49ed27e0-9859-431a-ab6c-15a7a6ed13cc', 'Reims', 'Marne', '67 Rue Jacquart, 51100 Reims', '+33 3 26 07 35 07', 'www.champagne-palmer.fr', 1947, 'Coopérative Palmer', 'Cooperativa', NULL, 'Rémi Vervier', NULL, 390, NULL, 35, 40, 25, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', 2000000, NULL, NULL, true, false,
 'Cooperativa di qualità fondata nel 1947 da sette viticoltori di Reims con vigne nei principali crus della Montagne de Reims. Palmer & Co ha costruito un''identità stilistica riconoscibile con champagne di grande fruibilità e ottimo rapporto qualità-prezzo. Il Blanc de Blancs e i millesimati sono le referenze più apprezzate dalla critica.', 'La cooperativa come strumento di eccellenza: Palmer & Co dimostra che qualità e cooperazione non sono opposti, con champagne di grande accessibilità e carattere genuino.', '€€€', false),

('Réaut', 'reaut', 'RM', '08daee1e-4c45-4961-9e87-d20c6bac0972', NULL, 'Marne', NULL, NULL, NULL, NULL, 'Famille Réaut', 'Indipendente', NULL, NULL, NULL, NULL, NULL, 40, 30, 30, ARRAY[]::text[], 'pneumatica', 'acciaio inox', 'svolta', NULL, NULL, NULL, false, false,
 'Piccolo vigneron della Valle della Marna con champagne di carattere artigianale. Produzione in piccole quantità con forte identità territoriale e approccio familiare alla viticoltura champenoise.', 'Artigianalità autentica e rispetto per il terroir della Valle della Marna.', '€€', false),

